cat > /tmp/repro_mudselect_focus_validation.sh <<'EOF'
#!/usr/bin/env bash
REPRO_DIR=/tmp/mudselect-focus-repro
mkdir -p "$REPRO_DIR"
cat > "$REPRO_DIR/MudSelectFocusRepro.csproj" <<'CSProj'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <Nullable>enable</Nullable>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="bunit" Version="2.7.2" />
    <ProjectReference Include="/workspace/MudBlazor/src/MudBlazor/MudBlazor.csproj" />
  </ItemGroup>
</Project>
CSProj
cat > "$REPRO_DIR/Program.cs" <<'CS'
using System;
using Bunit;
using Microsoft.AspNetCore.Components.Web;
using Microsoft.Extensions.DependencyInjection;
using MudBlazor;
using MudBlazor.Services;

static BunitContext CreateContext()
{
    var ctx = new BunitContext();
    ctx.JSInterop.Mode = JSRuntimeMode.Loose;
    ctx.Services.AddMudServices(options => options.PopoverOptions.CheckForPopoverProvider = false);
    return ctx;
}

static async Task<bool> TriggerFocusOutAsync(IRenderedComponent<MudSelect<string>> rendered)
{
    var outer = rendered.Find("div.mud-select[id]");
    await outer.TriggerEventAsync("onfocusout", new FocusEventArgs { Type = "focusout" });
    return true;
}

var requiredContext = CreateContext();
var required = requiredContext.Render<MudSelect<string>>(parameters => parameters
    .Add(p => p.Label, "Car")
    .Add(p => p.Required, true));
Console.WriteLine($"Required initial: touched={required.Instance.Touched}, hasErrors={required.Instance.HasErrors}, errorText='{required.Instance.GetErrorText()}'");
await TriggerFocusOutAsync(required);
Console.WriteLine($"Required after focusout: touched={required.Instance.Touched}, hasErrors={required.Instance.HasErrors}, errorText='{required.Instance.GetErrorText()}'");
var requiredPass = required.Instance.Touched && required.Instance.HasErrors && required.Instance.GetErrorText() == required.Instance.RequiredError;

var optionalContext = CreateContext();
var optional = optionalContext.Render<MudSelect<string>>(parameters => parameters.Add(p => p.Label, "Optional"));
await TriggerFocusOutAsync(optional);
Console.WriteLine($"Optional after focusout: touched={optional.Instance.Touched}, hasErrors={optional.Instance.HasErrors}, errorText='{optional.Instance.GetErrorText()}'");
var optionalPass = optional.Instance.Touched && !optional.Instance.HasErrors;

var openContext = CreateContext();
var openRequired = openContext.Render<MudSelect<string>>(parameters => parameters
    .Add(p => p.Label, "OpenRequired")
    .Add(p => p.Required, true));
await openRequired.InvokeAsync(openRequired.Instance.OpenMenu);
await TriggerFocusOutAsync(openRequired);
Console.WriteLine($"Open required after focusout: touched={openRequired.Instance.Touched}, hasErrors={openRequired.Instance.HasErrors}, errorText='{openRequired.Instance.GetErrorText()}'");
var openPass = !openRequired.Instance.Touched && !openRequired.Instance.HasErrors;

if (requiredPass && optionalPass && openPass)
{
    Console.WriteLine("PASS: MudSelect focus loss validation and edge cases behave correctly.");
    return 0;
}

Console.WriteLine($"FAIL: requiredPass={requiredPass}, optionalPass={optionalPass}, openPass={openPass}");
return 2;
CS

dotnet restore "$REPRO_DIR/MudSelectFocusRepro.csproj" --nologo >/dev/null
RESULT=$?
if [ "$RESULT" -ne 0 ]; then
  exit "$RESULT"
fi
dotnet run --project "$REPRO_DIR/MudSelectFocusRepro.csproj" --no-restore /p:SkipBunCompile=true --nologo
exit $?
EOF
chmod +x /tmp/repro_mudselect_focus_validation.sh
/tmp/repro_mudselect_focus_validation.sh; echo REPRO_EXIT:$?

